def find_overdue_gates(
    initiatives: list[PortfolioInitiative],
    today: date,
) -> list[tuple[PortfolioInitiative, int]]:
    """Return (initiative, days_overdue) pairs for active initiatives past their gate date."""
    overdue = []
    for ini in initiatives:
        if ini.current_stage in (Stage.KILLED, Stage.PARKED):
            continue
        lg = ini.last_gate()
        if lg and lg.next_gate_date and today > lg.next_gate_date:
            days = (today - lg.next_gate_date).days
            overdue.append((ini, days))
    return sorted(overdue, key=lambda x: x[1], reverse=True)


overdue = find_overdue_gates(initiatives, today)
if overdue:
    print("OVERDUE GATE ALERTS")
    for ini, days in overdue:
        print(f"  {ini.name} ({ini.id}): gate overdue by {days} day(s)")
else:
    print("No overdue gates.")
